mapper.select:
select * from course


        and type = #{type}


        and level = #{level}


        and scenario = #{scenario}


order by createtime desc

select c.* from course c
where c.id not in (
    select course_id from study_record where user_id = #{userId}
) and c.id not in (
    select target_id from collection where user_id = #{userId} and target_type = 'course'
)
and (
    c.type in (
        select type from course where id in (
            select course_id from study_record where user_id = #{userId}
            union
            select target_id from collection where user_id = #{userId} and target_type = 'course'
        )
    )
    or (
        (select count(*) from study_record where user_id = #{userId}) + 
        (select count(*) from collection where user_id = #{userId} and target_type = 'course')
    ) = 0
)
order by c.view_count desc
limit 5
